import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from './components/layout/SimpleNotFoundPage';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';

const DevPage = React.lazy(() => import('./dev/DevPage'));

// ── Sản Xuất / MES (sx) ──────────────────────────────────────────────────────
const LsxListPage                   = React.lazy(() => import('./pages/sx/LsxListPage'));
const LsxFormPage                   = React.lazy(() => import('./pages/sx/LsxFormPage'));
const BomListPage                   = React.lazy(() => import('./pages/sx/BomListPage'));
const BomFormPage                   = React.lazy(() => import('./pages/sx/BomFormPage'));
const CongDoanPage                  = React.lazy(() => import('./pages/sx/CongDoanPage'));
const DinhMucKhoanPage              = React.lazy(() => import('./pages/sx/DinhMucKhoanPage'));
const SanPhamHoanThanhPage          = React.lazy(() => import('./pages/sx/SanPhamHoanThanhPage'));
const NangSuatPage                  = React.lazy(() => import('./pages/sx/NangSuatPage'));
const BaoCaoThanhPhamDonHangPage    = React.lazy(() => import('./pages/sx/BaoCaoThanhPhamDonHangPage'));

const Suspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);
const AppShell = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const Root: React.FC = () => (
  <Provider store={store}>
    <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
      <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
          {showDevNav && (
            <>
              <Route index element={<Navigate to="/dev" replace />} />
              <Route path="dev" element={<Suspense><DevPage /></Suspense>} />
            </>
          )}
          <Route path="sx" element={<Navigate to="sx/lsx" replace />} />
          <Route path="sx/lsx"                     element={<Suspense><LsxListPage /></Suspense>} />
          <Route path="sx/lsx/them"               element={<Suspense><LsxFormPage /></Suspense>} />
          <Route path="sx/lsx/:id"                element={<Suspense><LsxFormPage /></Suspense>} />
          <Route path="sx/bom"                    element={<Suspense><BomListPage /></Suspense>} />
          <Route path="sx/bom/them"               element={<Suspense><BomFormPage /></Suspense>} />
          <Route path="sx/bom/:id"                element={<Suspense><BomFormPage /></Suspense>} />
          <Route path="sx/cong-doan"              element={<Suspense><CongDoanPage /></Suspense>} />
          <Route path="sx/dinh-muc-khoan"         element={<Suspense><DinhMucKhoanPage /></Suspense>} />
          <Route path="sx/san-pham-hoan-thanh"    element={<Suspense><SanPhamHoanThanhPage /></Suspense>} />
          <Route path="sx/nang-suat"             element={<Suspense><NangSuatPage /></Suspense>} />
          <Route path="sx/bao-cao-don-hang"      element={<Suspense><BaoCaoThanhPhamDonHangPage /></Suspense>} />
          <Route path="*" element={<SimpleNotFoundPage />} />
        </Route>
      </Routes>
    </Router>
  </Provider>
);

export default Root;
